module RefModule(
    input clk,
    input rst,
    input [3:0] in_signal,
    output reg [1:0] out_signal
);

reg [1:0] obf_count;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        obf_count <= 2'b00;
        out_signal <= 2'b00;
    end else begin
        obf_count <= obf_count + 1;
        if (obf_count == 2'b01) begin
            out_signal <= in_signal[3:2]; // take the two MSBs of the input
        end
    end
end

endmodule
